        public static string TokenMetaAttribute(MetaAttribute metaAttribute)
        {
            switch (metaAttribute)
            {
                case MetaAttribute.Epoch: return "";
                case MetaAttribute.TimeUnit: return "";
                case MetaAttribute.SemanticType: return "";
                case MetaAttribute.Presence: return "required";
            }

            return "";
        }

        public const int TokenHeaderSize = 2;
        
        public int TokenLength()
        {
            _buffer.CheckLimit(_parentMessage.Limit + 2);
            return (int)_buffer.Uint16GetLittleEndian(_parentMessage.Limit);
        }

        public int GetToken(byte[] dst, int dstOffset, int length) =>
            GetToken(new Span<byte>(dst, dstOffset, length));

        public int GetToken(Span<byte> dst)
        {
            const int sizeOfLengthField = 2;
            int limit = _parentMessage.Limit;
            _buffer.CheckLimit(limit + sizeOfLengthField);
            int dataLength = (int)_buffer.Uint16GetLittleEndian(limit);
            int bytesCopied = Math.Min(dst.Length, dataLength);
            _parentMessage.Limit = limit + sizeOfLengthField + dataLength;
            _buffer.GetBytes(limit + sizeOfLengthField, dst.Slice(0, bytesCopied));

            return bytesCopied;
        }
        
