        public int SetToken(ReadOnlySpan<byte> src)
        {
            const int sizeOfLengthField = 2;
            int limit = _parentMessage.Limit;
            _parentMessage.Limit = limit + sizeOfLengthField + src.Length;
            _buffer.Uint16PutLittleEndian(limit, (ushort)src.Length);
            _buffer.SetBytes(limit + sizeOfLengthField, src);

            return src.Length;
        }

        public string GetToken()
        {
            const int sizeOfLengthField = 2;
            int limit = _parentMessage.Limit;
            _buffer.CheckLimit(limit + sizeOfLengthField);
            int dataLength = (int)_buffer.Uint16GetLittleEndian(limit);
