        public override string ToString()
        {
            var sb = new StringBuilder(100);
            var m = new BasketOrderRequestMessage();
            m.WrapForDecode(_buffer, _offset, _actingBlockLength, _actingVersion);
            m.BuildString(sb);
            return sb.ToString();
        }

        internal void BuildString(StringBuilder builder)
        {
            if (_buffer == null)
            {
                throw new ArgumentNullException("_buffer");
            }

            int originalLimit = this.Limit;
            this.Limit = _offset + _actingBlockLength;
            builder.Append("[BasketOrderRequestMessage](sbeTemplateId=");
            builder.Append(BasketOrderRequestMessage.TemplateId);
            builder.Append("|sbeSchemaId=");
            builder.Append(BasketOrderRequestMessage.SchemaId);
            builder.Append("|sbeSchemaVersion=");
            if (_parentMessage._actingVersion != BasketOrderRequestMessage.SchemaVersion)
            {
                builder.Append(_parentMessage._actingVersion);
                builder.Append('/');
            }
            builder.Append(BasketOrderRequestMessage.SchemaVersion);
            builder.Append("|sbeBlockLength=");
            if (_actingBlockLength != BasketOrderRequestMessage.BlockLength)
            {
                builder.Append(_actingBlockLength);
                builder.Append('/');
            }
            builder.Append(BasketOrderRequestMessage.BlockLength);
            builder.Append("):");

            builder.Append("BasketOrderRows=[");
            var basketOrderRows = this.BasketOrderRows;
            if (basketOrderRows.Count > 0)
            {
                var first = true;
                while (basketOrderRows.HasNext)
                {
                    if (!first)
                    {
                        builder.Append(',');
                    }
                    first = false;
                    basketOrderRows.Next().BuildString(builder);
                }
            }
            builder.Append("]");
            builder.Append('|');
            builder.Append("Token=");
            builder.Append('\'').Append(GetToken()).Append('\'');
            builder.Append('|');
            builder.Append("ClientOrderId=");
            builder.Append('\'').Append(GetClientOrderId()).Append('\'');

            this.Limit = originalLimit;

        }
